args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?rebrandDate WHERE {
  wd:Q2060087 wdt:P2271 ?rebrandDate .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?name ?startTime ?endTime WHERE {
  wd:Q2060087 p:P1448 ?statement .
  ?statement ps:P1448 ?name .
  OPTIONAL { ?statement pq:P580 ?startTime }
  OPTIONAL { ?statement pq:P582 ?endTime }
}

best_attempt.sparql:
SELECT (YEAR(?time) AS ?year) WHERE {
  wd:Q2060087 p:P1855 ?statement .
  ?statement ps:P1855 ?previousName .
  ?statement pq:P585 ?time .
  FILTER(LCASE(?previousName) = "vh1 classic")
}
